class Solution {
public:
    int countDigitOne(int n) {
        int count = 0;
        long long i = 1;
        while (i <= n) {
            long long divider = i * 10;
            count += (n / divider) * i + min(max(n % divider - i + 1, 0LL), i);
            i *= 10;
        }
        return count;
    }
};
